"""Agentic loop: OpenAI-совместимый клиент + tool-calling."""

from __future__ import annotations

import sys
from dataclasses import dataclass
from typing import Any

from openai import OpenAI

from .config import Config
from .prompts import system_prompt
from .tools import TOOL_SCHEMAS, ToolContext, dispatch


@dataclass
class AgentResult:
    answer: str
    supporting_data: dict[str, Any]
    sql_attempts: int
    iterations: int


def _make_client(cfg: Config) -> OpenAI:
    return OpenAI(base_url=cfg.api_url, api_key=cfg.api_key)


def _log(msg: str, *, verbose: bool) -> None:
    if verbose:
        print(msg, file=sys.stderr, flush=True)


def _serialise_tool_calls(tool_calls: Any) -> list[dict[str, Any]]:
    """Сериализует tool_calls модели обратно в assistant-сообщение."""
    out: list[dict[str, Any]] = []
    for tc in tool_calls or []:
        out.append({
            "id": tc.id,
            "type": "function",
            "function": {
                "name": tc.function.name,
                "arguments": tc.function.arguments or "{}",
            },
        })
    return out


def run_agent(
    question: str,
    cfg: Config | None = None,
    *,
    max_iterations: int = 8,
    verbose: bool = True,
    temperature: float = 0.0,
) -> AgentResult:
    """Запускает агентный цикл и возвращает финальный ответ.

    Цикл: chat → tool-calls → tool-results → chat → ... → final_answer.
    """
    cfg_eff: Config = cfg if cfg is not None else Config.from_env()
    client = _make_client(cfg_eff)
    ctx = ToolContext(cfg=cfg_eff)

    messages: list[dict[str, Any]] = [
        {"role": "system", "content": system_prompt()},
        {"role": "user", "content": question},
    ]

    iterations = 0
    last_text: str = ""

    for iteration in range(1, max_iterations + 1):
        iterations = iteration
        _log(f"[agent] iteration {iteration}", verbose=verbose)
        completion = client.chat.completions.create(
            model=cfg_eff.sql_model,
            messages=messages,  # type: ignore[arg-type]
            tools=TOOL_SCHEMAS,  # type: ignore[arg-type]
            tool_choice="auto",
            temperature=temperature,
        )
        msg = completion.choices[0].message
        tool_calls = getattr(msg, "tool_calls", None)
        content = msg.content or ""
        if content:
            last_text = content

        if not tool_calls:
            # Модель не сделала tool-вызов — насильно просим final_answer
            _log("[agent] no tool_calls, nudging model", verbose=verbose)
            messages.append({"role": "assistant", "content": content})
            messages.append({
                "role": "user",
                "content": (
                    "Ты не вызвал tool. Если уже есть данные из execute_sql — вызови "
                    "validate_result, затем final_answer. Если данных нет — сначала "
                    "execute_sql. Не отвечай свободным текстом."
                ),
            })
            continue

        # Регистрируем сообщение ассистента (с tool_calls) — обязательно для tool-message протокола
        messages.append({
            "role": "assistant",
            "content": content,
            "tool_calls": _serialise_tool_calls(tool_calls),
        })

        for tc in tool_calls:
            name = tc.function.name
            raw_args = tc.function.arguments or "{}"
            _log(f"[agent] tool: {name} args={raw_args[:200]}", verbose=verbose)
            tool_result = dispatch(name, raw_args, ctx)
            _log(f"[agent] tool result: {tool_result[:200]}", verbose=verbose)
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "name": name,
                "content": tool_result,
            })

        if ctx.final is not None:
            return AgentResult(
                answer=ctx.final["text"],
                supporting_data=ctx.final.get("supporting_data") or {},
                sql_attempts=ctx.sql_attempts,
                iterations=iterations,
            )

    # Лимит итераций исчерпан — попробуем «вытащить» ответ из state
    fallback = _force_final_answer(client, cfg, messages, ctx, verbose=verbose)
    if fallback is not None:
        return fallback

    return AgentResult(
        answer=(
            last_text.strip()
            or "Не удалось сформировать ответ: исчерпан лимит итераций."
        ),
        supporting_data={"sql": ctx.last_sql or "", "key_numbers": {}},
        sql_attempts=ctx.sql_attempts,
        iterations=iterations,
    )


def _force_final_answer(
    client: OpenAI,
    cfg: Config,
    messages: list[dict[str, Any]],
    ctx: ToolContext,
    *,
    verbose: bool,
) -> AgentResult | None:
    """Если loop завершился без final_answer, делаем ещё один шаг с tool_choice=final_answer."""
    if ctx.last_result is None:
        return None
    _log("[agent] forcing final_answer", verbose=verbose)
    messages = list(messages) + [{
        "role": "user",
        "content": (
            "Срочно вызови final_answer на основе уже имеющихся данных. "
            "Не делай больше других tool-вызовов."
        ),
    }]
    try:
        completion = client.chat.completions.create(
            model=cfg.sql_model,
            messages=messages,  # type: ignore[arg-type]
            tools=TOOL_SCHEMAS,  # type: ignore[arg-type]
            tool_choice={
                "type": "function",
                "function": {"name": "final_answer"},
            },
            temperature=0.0,
        )
    except Exception as exc:
        _log(f"[agent] force-final failed: {exc}", verbose=verbose)
        return None
    tool_calls = getattr(completion.choices[0].message, "tool_calls", None) or []
    for tc in tool_calls:
        if tc.function.name == "final_answer":
            dispatch("final_answer", tc.function.arguments or "{}", ctx)
            if ctx.final is not None:
                return AgentResult(
                    answer=ctx.final["text"],
                    supporting_data=ctx.final.get("supporting_data") or {},
                    sql_attempts=ctx.sql_attempts,
                    iterations=len(messages),
                )
    return None

"""Tool-определения для агента (OpenAI tool-calling format) + диспетчер."""

from __future__ import annotations

import json
from dataclasses import dataclass, field
from typing import Any, Callable

from .config import Config
from .db import QueryResult, SQLError, run_query
from .schema import describe_table, list_known_tables


# --- Tool JSON-schemas (для tools= параметра OpenAI Chat Completions) ---

TOOL_SCHEMAS: list[dict[str, Any]] = [
    {
        "type": "function",
        "function": {
            "name": "inspect_schema",
            "description": (
                "Возвращает описание таблицы и её полей из бизнес-словаря "
                "(назначение, типы, категории, агрегации, примеры SQL). "
                "Вызывай, если нужно уточнить структуру таблицы."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "table": {
                        "type": "string",
                        "description": "Имя таблицы (например, 'client_product').",
                    }
                },
                "required": ["table"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "execute_sql",
            "description": (
                "Выполняет SELECT/WITH запрос в Oracle и возвращает таблицу "
                "(columns, rows, row_count, truncated). Read-only. "
                "Один statement, без точки с запятой на конце."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "sql": {
                        "type": "string",
                        "description": "Oracle SQL-запрос (SELECT или WITH).",
                    }
                },
                "required": ["sql"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "validate_result",
            "description": (
                "Sanity-проверка результата последнего execute_sql. "
                "Возвращает {ok: bool, issues: [..]}. Обязательный шаг перед final_answer."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "min_rows": {
                        "type": "integer",
                        "description": "Минимально ожидаемое число строк (включая 0).",
                    },
                    "max_rows": {
                        "type": "integer",
                        "description": "Максимально ожидаемое число строк (опционально).",
                    },
                    "required_non_null_columns": {
                        "type": "array",
                        "items": {"type": "string"},
                        "description": "Колонки, в которых ни одно значение не должно быть NULL.",
                    },
                    "numeric_ranges": {
                        "type": "object",
                        "description": (
                            "Карта column->[min, max]: значения колонки должны попадать в [min, max]. "
                            "min/max могут быть null если нужна только одна граница."
                        ),
                        "additionalProperties": {
                            "type": "array",
                            "items": {"type": ["number", "null"]},
                            "minItems": 2,
                            "maxItems": 2,
                        },
                    },
                    "expectation_note": {
                        "type": "string",
                        "description": "Что именно ты ожидаешь увидеть в результате (для аудита).",
                    },
                },
                "required": ["min_rows"],
            },
        },
    },
    {
        "type": "function",
        "function": {
