@dataclass
class ToolContext:
    """Состояние, передаваемое между вызовами тулзов в одной итерации."""

    cfg: Config
    last_result: QueryResult | None = None
    last_sql: str | None = None
    history: list[dict[str, Any]] = field(default_factory=list)
    final: dict[str, Any] | None = None
    sql_attempts: int = 0


# --- Реализации тулзов ---


def _tool_inspect_schema(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    table = (args.get("table") or "").strip() or "client_product"
    try:
        return describe_table(table)
    except ValueError:
        return {
            "error": f"Таблица '{table}' не найдена",
            "known_tables": list_known_tables(),
        }


def _tool_execute_sql(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    sql = (args.get("sql") or "").strip()
    if not sql:
        return {"error": "Пустой SQL"}
    ctx.sql_attempts += 1
    try:
        result = run_query(sql, ctx.cfg)
        ctx.last_result = result
        ctx.last_sql = sql
        out = result.to_dict()
        # Помогаем модели понять, как трактовать пустоту
        if result.row_count == 0:
            out["note"] = (
                "Результат пустой: возможно, нет данных за запрошенный период "
                "или фильтр слишком узкий. Уточни запрос."
            )
        return out
    except SQLError as exc:
        return {"error": str(exc), "sql": sql}


def _check_range(values: list[Any], lo: Any, hi: Any) -> tuple[bool, str]:
    bad: list[Any] = []
    for v in values:
        if v is None:
            continue
        try:
            x = float(v)
        except (TypeError, ValueError):
            bad.append(v)
            continue
        if lo is not None and x < float(lo):
            bad.append(v)
        elif hi is not None and x > float(hi):
            bad.append(v)
    if not bad:
        return True, ""
    sample = bad[:3]
    return False, f"найдены значения вне диапазона: {sample}"


def _tool_validate_result(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    if ctx.last_result is None:
        return {
            "ok": False,
            "issues": ["Нет результата для валидации: сначала вызови execute_sql"],
        }
    res = ctx.last_result
    issues: list[str] = []

    min_rows = int(args.get("min_rows", 0))
    if res.row_count < min_rows:
        issues.append(
            f"row_count={res.row_count} меньше ожидаемого минимума {min_rows}"
        )

    max_rows = args.get("max_rows")
    if max_rows is not None and res.row_count > int(max_rows):
        issues.append(
            f"row_count={res.row_count} больше ожидаемого максимума {max_rows}"
        )

    if res.truncated:
        issues.append(
            "результат обрезан по лимиту строк — уточни запрос или используй агрегацию"
        )

    col_idx = {c.upper(): i for i, c in enumerate(res.columns)}

    for col in args.get("required_non_null_columns") or []:
        i = col_idx.get(str(col).upper())
        if i is None:
            issues.append(f"колонка {col!r} отсутствует в результате")
            continue
        nulls = sum(1 for r in res.rows if r[i] is None)
        if nulls > 0:
            issues.append(f"в колонке {col} найдено {nulls} NULL-значений")

    for col, bounds in (args.get("numeric_ranges") or {}).items():
        i = col_idx.get(str(col).upper())
        if i is None:
            issues.append(f"колонка {col!r} отсутствует в результате")
            continue
        if not (isinstance(bounds, (list, tuple)) and len(bounds) == 2):
            issues.append(f"для {col} ожидался диапазон [min, max]")
            continue
        lo, hi = bounds
        ok, msg = _check_range([r[i] for r in res.rows], lo, hi)
        if not ok:
            issues.append(f"{col}: {msg}")

    return {
        "ok": not issues,
        "issues": issues,
        "row_count": res.row_count,
        "columns": res.columns,
        "expectation_note": args.get("expectation_note", ""),
    }


def _tool_final_answer(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    text = (args.get("text") or "").strip()
    if not text:
        return {"error": "final_answer.text обязателен и не должен быть пустым"}
    payload = {
        "text": text,
        "supporting_data": args.get("supporting_data") or {
            "sql": ctx.last_sql or "",
            "key_numbers": {},
        },
    }
    ctx.final = payload
    return {"ok": True}


TOOL_HANDLERS: dict[str, Callable[[dict[str, Any], ToolContext], dict[str, Any]]] = {
    "inspect_schema": _tool_inspect_schema,
    "execute_sql": _tool_execute_sql,
    "validate_result": _tool_validate_result,
    "final_answer": _tool_final_answer,
}


def dispatch(name: str, raw_arguments: str, ctx: ToolContext) -> str:
    """Маршрутизатор tool-вызовов. Возвращает JSON-строку (для tool message).

    Любые ошибки парсинга/исполнения превращаются в JSON с ключом `error`,
    чтобы модель могла их прочитать и скорректироваться.
    """
    handler = TOOL_HANDLERS.get(name)
    if handler is None:
        return json.dumps(
            {"error": f"Неизвестный tool: {name}", "known": list(TOOL_HANDLERS)},
            ensure_ascii=False,
        )
    try:
        args = json.loads(raw_arguments) if raw_arguments else {}
        if not isinstance(args, dict):
            return json.dumps(
                {"error": "tool arguments должны быть JSON-объектом"},
                ensure_ascii=False,
            )
    except json.JSONDecodeError as exc:
        return json.dumps(
            {"error": f"Невалидный JSON в аргументах: {exc}", "raw": raw_arguments},
            ensure_ascii=False,
        )
    result = handler(args, ctx)
    return json.dumps(result, ensure_ascii=False, default=str)

"""Тонкий wrapper над oracledb (thin-mode, без Oracle client)."""

from __future__ import annotations

import datetime as _dt
import decimal as _decimal
import re
from dataclasses import dataclass, field
from typing import Any

import oracledb

from .config import Config

_FORBIDDEN_PATTERN = re.compile(
    r"\b(INSERT|UPDATE|DELETE|MERGE|DROP|TRUNCATE|ALTER|CREATE|GRANT|REVOKE|"
    r"COMMIT|ROLLBACK|SAVEPOINT|EXEC|EXECUTE|CALL|BEGIN|DECLARE)\b",
    re.IGNORECASE,
)


class SQLError(RuntimeError):
    """Любая ошибка при выполнении SQL — синтаксис, доступ, политика."""


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    truncated: bool = False
    row_count: int = field(init=False)

    def __post_init__(self) -> None:
        self.row_count = len(self.rows)

    def to_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
        }


def _normalize_sql(sql: str) -> str:
    s = sql.strip()
    while s.endswith(";"):
        s = s[:-1].rstrip()
    return s


def validate_select(sql: str) -> str:
    """Гарантирует, что переданный SQL — единичный SELECT/WITH запрос.

    Защита от случайной DDL/DML модификации тестовой БД.
    """
    sql = _normalize_sql(sql)
    if not sql:
        raise SQLError("Пустой SQL")
    if ";" in sql:
        raise SQLError("Только один SQL-statement за вызов (без ';')")
    head = sql.lstrip("(").lstrip()[:6].upper()
    if not (head.startswith("SELECT") or head.startswith("WITH")):
        raise SQLError(
            "Разрешены только SELECT/WITH запросы (read-only режим)"
        )
    if _FORBIDDEN_PATTERN.search(sql):
        raise SQLError(
            "В SQL найдены запрещённые ключевые слова (DDL/DML/PLSQL)"
        )
    return sql


def _coerce(value: Any) -> Any:
    """Приводит Oracle типы к JSON-friendly значениям."""
    if value is None:
        return None
    if isinstance(value, _dt.datetime):
        return value.strftime("%Y-%m-%d %H:%M:%S")
    if isinstance(value, _dt.date):
        return value.strftime("%Y-%m-%d")
    if isinstance(value, _decimal.Decimal):
        if value == value.to_integral_value():
            return int(value)
        return float(value)
    if isinstance(value, oracledb.LOB):
        try:
            return value.read()
        except Exception:
            return str(value)
    if isinstance(value, bytes):
        try:
            return value.decode("utf-8", errors="replace")
        except Exception:
            return repr(value)
    return value


def run_query(
    sql: str,
    cfg: Config,
    *,
    max_rows: int = 500,
    fetch_arraysize: int = 200,
) -> QueryResult:
    """Выполняет SELECT и возвращает строки + колонки.

    Все ошибки оборачиваются в `SQLError` с понятным сообщением.
    """
    safe_sql = validate_select(sql)
    try:
        with oracledb.connect(
            user=cfg.oracle_user,
            password=cfg.oracle_password,
            dsn=cfg.oracle_dsn,
        ) as conn:
            with conn.cursor() as cur:
                cur.arraysize = fetch_arraysize
                cur.execute(safe_sql)
                cols: list[str] = [
                    str(d[0]) for d in (cur.description or [])
                ]
                rows: list[list[Any]] = []
                truncated = False
                for raw in cur:
                    rows.append([_coerce(v) for v in raw])
                    if len(rows) >= max_rows:
                        # Проверяем, есть ли ещё хоть одна строка дальше.
                        extra = cur.fetchone()
                        if extra is not None:
                            truncated = True
                        break
                return QueryResult(columns=cols, rows=rows, truncated=truncated)
    except oracledb.Error as exc:
        # oracledb.Error содержит (Error,) с code и message
        err = exc.args[0] if exc.args else exc
        raise SQLError(f"Oracle error: {err}") from exc


